--

CREATE TABLE public.tracevision_tracevisionsessionstats (
    id integer NOT NULL,
    home_team_stats jsonb NOT NULL,
    away_team_stats jsonb NOT NULL,
    possession_data jsonb NOT NULL,
    tactical_analysis jsonb NOT NULL,
